1	// Structural tests for S06 documentation contracts.
2	// All tests use env!("CARGO_MANIFEST_DIR") for portable path resolution.
3	// T02 and T03 create the docs that make these tests pass.
4	
5	#[test]
6	fn readme_exists() {
7	    let root = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
8	    let file = root.join("README.md");
9	    assert!(file.exists(), "README.md must exist");
10	}
11	
12	#[test]
13	fn readme_has_installation_section() {
14	    let root = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
15	    let file = root.join("README.md");
16	    let contents = std::fs::read_to_string(&file).expect("failed to read README.md");
17	    assert!(
18	        contents.contains("## Installation"),
19	        "README.md must contain '## Installation'"
20	    );
21	}
