23	#[test]
24	fn readme_has_usage_section() {
25	    let root = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
26	    let file = root.join("README.md");
27	    let contents = std::fs::read_to_string(&file).expect("failed to read README.md");
28	    assert!(
29	        contents.contains("## Usage") || contents.contains("## Running"),
30	        "README.md must contain '## Usage' or '## Running'"
31	    );
