34	#[test]
35	fn readme_has_correct_project_name() {
36	    let root = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
37	    let file = root.join("README.md");
38	    let contents = std::fs::read_to_string(&file).expect("failed to read README.md");
39	    assert!(
40	        contents.contains("hd-linux-voice"),
41	        "README.md must contain 'hd-linux-voice'"
42	    );
43	    assert!(
44	        !contents.contains("vibe-attack"),
45	        "README.md must not reference 'vibe-attack' (stale project name)"
46	    );
47	}
